<module id="parallel2serial">
    <description>Parallel-to-serial converter converting 4-bit parallel data to 1-bit serial data.</description>
    <ports>
        <input id="clk">Clock signal used for synchronous operations.</input>
        <input id="rst_n">Reset signal. Defined as 0 for reset and 1 for reset signal inactive.</input>
        <input id="d" width_description="[3:0]">4-bit parallel data input.</input>
        <output id="valid_out">Valid signal indicating the availability of serial output.</output>
        <output id="dout">Serial output representing the converted data.</output>
    </ports>
    <parameter_description>
        <constant name="CNT_WIDTH" value="2">Width of the counter register.</constant>
    </parameter_description>
    <logic_description type="sequential_logic">
        <reg id="cnt" width="2">Counter register.</reg>
        <reg id="data" width="4">Data register.</reg>
        <reg id="valid" width="1">Valid signal register.</reg>
    </logic_description>
    <implementation>
        // Sequential logic for counter and data register
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                cnt <= 0;
                data <= 0;
                valid <= 0;
            end else begin
                if (cnt == 3) begin
                    data <= d;
                    cnt <= 0;
                    valid <= 1;
                end else begin
                    cnt <= cnt + 1;
                    valid <= 0;
                    data <= {data[2:0], data[3]};
                end
            end
        end

        // Assignments for outputs
        assign dout = data[3];
        assign valid_out = valid;
    </implementation>
</module>
```
